  /* ---------- helpers ---------- */
  function usd(n) {
    var opts = { style: "currency", currency: "USD", maximumFractionDigits: (n % 1 === 0 ? 0 : 2) };
    return n.toLocaleString("en-US", opts);
  }
  function fdate(iso) { return new Date(iso + "T00:00:00").toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" }); }
  function fshort(iso) { return new Date(iso + "T00:00:00").toLocaleDateString("en-US", { month: "short", day: "numeric" }); }
  function client(id) { for (var i = 0; i < CLIENTS.length; i++) if (CLIENTS[i].id === id) return CLIENTS[i]; return null; }
  function invById(id) { for (var i = 0; i < INVOICES.length; i++) if (INVOICES[i].id === id) return INVOICES[i]; return null; }
  function invTotal(inv) { var s = 0; for (var i = 0; i < inv.lines.length; i++) s += inv.lines[i].a; return s; }
  function daysOver(inv) { return Math.round((new Date(TODAY + "T00:00:00") - new Date(inv.due + "T00:00:00")) / 86400000); }
  function bucket(inv) { var d = daysOver(inv); if (d <= 0) return "current"; if (d <= 30) return "d1"; if (d <= 60) return "d31"; return "d61"; }
  function esc(s) { return String(s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;"); }

